// Define a shape (Interface)
interface Bird {
  fly(): void;
  layEgg(): void;
}

// This function expects a 'Bird'
function letItFly(bird: Bird) {
  bird.fly();
}

// This class is NOT named 'Bird', and does not 'extend' anything.

