function issueTaxCertificate(address _applicant, uint256 _amount) public payable {
    require(msg.value == _amount, "Incorrect payment amount");

    // 1.

 Atomic Minting
    if (issuerNode.sign(credentialHash)) {
        emit CertificateIssued(_applicant, validityDays, block.timestamp);
        // Transfer funds to Treasury
        treasury.transfer(msg.value);
    } else {
        // Revert if signing fails
        revert("Issuance Failed");
    }
}
```

